---@class LDisplayPrefabCtrl
local LDisplayPrefabCtrl = LxClass("LDisplayPrefabCtrl",nil)

function LDisplayPrefabCtrl:LDisplayPrefabCtrl()
    self._objList = {}
end

--[[
    local data =
    {
        trans,
        key = "mainRole",
        localPos = pos,
        pos = pos,
        resName = spineName,
        scale = Vector3,
        endFunc = function (spine)
        end,
        enableClick = true,
        sorting
    }
]]

function LDisplayPrefabCtrl:MakeObject(objData)
    local key = objData.key
    local objectData = self._objList[key]
    local displayObj = nil
    if objectData then
        objectData.objData = objData
        if objectData.isLoaded then
            self:OnLoaded(key)
        end
        displayObj = objectData.spine
    else
        displayObj = LDisplayPrefab:New()
        objectData = {displayObj = displayObj,objData = objData}
        self._objList[key] = objectData
        local trans = objData.trans
        local prefabName = objData.resName
        local prefabFolder = objData.folder
        displayObj:CreatePrefab(trans, prefabFolder,prefabName)
        displayObj:SetLoadedFunction(function()
            self:OnLoaded(key)
        end)
        displayObj:StartLoad()
    end

    return displayObj
end

function LDisplayPrefabCtrl:OnLoaded(key)

    local objectData = self._objList[key]
    if not objectData then
        return
    end
    objectData.isLoaded = true
    local displayObj = objectData.displayObj
    local objData = objectData.objData

    local dpTrans = displayObj:GetDisplayTrans()
    if not CS.IsValidObject(dpTrans) then
        return
    end
    if objData.pos then
        dpTrans.position =objData.pos
    end

    local localPos = objData.localPos or Vector3.zero
    dpTrans.localPosition = localPos

    if objData.scale then
        displayObj:SetScale(objData.scale)
    end

    if objData.sorting and objData.layer then
        displayObj:SetRenderPara(objData.layer,objData.sorting)
    end

    if objData.angle then
        local angle = objData.angle
        dpTrans.localRotation = Quaternion.Euler(angle.x,angle.y,angle.z)
    end

    if objData.endFunc then
        objData.endFunc(displayObj)
    end
end

function LDisplayPrefabCtrl:Clear()
    for k,v in pairs(self._objList) do
        local displayObj= v.displayObj
        displayObj:Destroy()
    end
    self._objList = {}
end

function LDisplayPrefabCtrl:DestroyByKey(key)
    local data = self._objList[key]
    self._objList[key] = nil
    if data then
        local displayObj = data.displayObj
        displayObj:Destroy()
    end

end

function LDisplayPrefabCtrl:FindObjByKey(key)
    local data = self._objList[key]
    if data then
        return data.displayObj
    end
end


return LDisplayPrefabCtrl